WITH org_hierarchy AS (
WITH RECURSIVE org_hierarchy AS (
-- 基础查询：选择起始部门 SELECT id, parent_id FROM org_department WHERE id = '2025031210051899642935718752256' -- 游仙的部门ID UNION ALL -- 递归查询：查找所有子部门 SELECT o.id, o.parent_id FROM org_department o JOIN org_hierarchy oh ON o.parent_id = oh.id ) SELECT ou.id as userId,oud.department_id FROM org_user ou INNER JOIN org_user_department oud ON ou.id = oud.user_id INNER JOIN org_hierarchy oh ON oh.id = oud.department_id WHERE ou.is_deleted = 0 AND ou.id = #{userId}

WITH org_hierarchy AS (
WITH RECURSIVE org_hierarchy AS (
-- 基础查询：选择起始部门 SELECT id, parent_id FROM org_department WHERE id = '2025031210051899642935718752256' -- 游仙的部门ID UNION ALL -- 递归查询：查找所有子部门 SELECT o.id, o.parent_id FROM org_department o JOIN org_hierarchy oh ON o.parent_id = oh.id ) SELECT id AS departmentId FROM org_hierarchy where id = #{deptId}
